.darma-loader-darma-custom-252 {
  color: var(--loader-color, #9333ea);
  height: 27px;
  aspect-ratio: 5;
  --c: currentColor 90deg,#0000 0;
  background:
   conic-gradient(from 135deg at top   ,var(--c)),
   conic-gradient(from -45deg at bottom,var(--c)) 12.5% 100%;
  background-size: 20% 50%;
  background-repeat: repeat-x;
  clip-path: inset(0 100% 0 0);
  animation: 
    darma-loader-darma-custom-252-l13-0 2.5s infinite steps(11,jump-none) alternate,
    darma-loader-darma-custom-252-l13-1 5s infinite steps(1);
}
@keyframes darma-loader-darma-custom-252-l13-0{
  to {clip-path: inset(0)}
}
@keyframes darma-loader-darma-custom-252-l13-1{
  50% {scale: -1 1}
}

